// Use this method to send a game. On success, the sent Message is returned.
//
// See https://core.telegram.org/bots/api#sendgame
type SendGameMethod struct { 
    // Unique identifier for the target chat or username of the target bot in the
// format @username. Games can't be sent to channel direct messages chats and
// channel chats.
    ChatID ChatID `json:"chat_id"` 
    // Short name of the game, serves as the unique identifier for the game. Set up
// your games via @BotFather.
    GameShortName string `json:"game_short_name"` 
    // Unique identifier of the business connection on behalf of which the message
// will be sent
    BusinessConnectionID *string `json:"business_connection_id,omitempty"` 
    // Unique identifier for the target message thread (topic) of a forum; for forum
// supergroups and private chats of bots with forum topic mode enabled only
    MessageThreadID *int64 `json:"message_thread_id,omitempty"` 
    // Sends the message silently. Users will receive a notification with no sound.
    DisableNotification *bool `json:"disable_notification,omitempty"` 
    // Protects the contents of the sent message from forwarding and saving
    ProtectContent *bool `json:"protect_content,omitempty"` 
    // Pass True to allow up to 1000 messages per second, ignoring broadcasting
// limits for a fee of 0.1 Telegram Stars per message. The relevant Stars will
// be withdrawn from the bot's balance.
    AllowPaidBroadcast *bool `json:"allow_paid_broadcast,omitempty"` 
    // Unique identifier of the message effect to be added to the message; for
// private chats only
    MessageEffectID *string `json:"message_effect_id,omitempty"` 
    // Description of the message to reply to
    ReplyParameters *ReplyParameters `json:"reply_parameters,omitempty"` 
    // A JSON-serialized object for an inline keyboard. If empty, one 'Play
// game_title' button will be shown. If not empty, the first button must launch
// the game.
    ReplyMarkup *InlineKeyboardMarkup `json:"reply_markup,omitempty"`
}

func (m SendGameMethod) Call(ctx context.Context, conn Connection) (Message, error) {
	payload := NewMultipartPayload() 
	if err := m.ChatID.Write(payload, "chat_id"); err != nil {
		return Message{}, err
	} 
	if err := NewStringPart(m.GameShortName).Write(payload, "game_short_name"); err != nil {
		return Message{}, err
	} 
	if m.BusinessConnectionID != nil {
		if err := NewStringPart(*m.BusinessConnectionID).Write(payload, "business_connection_id"); err != nil {
			return Message{}, err
		}
	} 
	if m.MessageThreadID != nil {
		if err := NewInt64Part(*m.MessageThreadID).Write(payload, "message_thread_id"); err != nil {
			return Message{}, err
		}
	} 
	if m.DisableNotification != nil {
		if err := NewBoolPart(*m.DisableNotification).Write(payload, "disable_notification"); err != nil {
			return Message{}, err
		}
	} 
	if m.ProtectContent != nil {
		if err := NewBoolPart(*m.ProtectContent).Write(payload, "protect_content"); err != nil {
			return Message{}, err
		}
	} 
	if m.AllowPaidBroadcast != nil {
		if err := NewBoolPart(*m.AllowPaidBroadcast).Write(payload, "allow_paid_broadcast"); err != nil {
			return Message{}, err
		}
	} 
	if m.MessageEffectID != nil {
		if err := NewStringPart(*m.MessageEffectID).Write(payload, "message_effect_id"); err != nil {
			return Message{}, err
		}
	} 
	if m.ReplyParameters != nil {
		if err := m.ReplyParameters.Write(payload, "reply_parameters"); err != nil {
			return Message{}, err
		}
	} 
	if m.ReplyMarkup != nil {
		if err := m.ReplyMarkup.Write(payload, "reply_markup"); err != nil {
			return Message{}, err
		}
	} 
	var resp Message
	err := conn.Do(ctx, MethodSendGame, payload, &resp)
	if err != nil {
		return Message{}, fmt.Errorf("%s: %w", MethodSendGame, err)
	}
	return resp, nil
}  
// Use this method to set the score of the specified user in a game message. On
// success, if the message is not an inline message, the Message is returned,
// otherwise True is returned. Returns an error, if the new score is not greater
// than the user's current score in the chat and force is False.
//
// See https://core.telegram.org/bots/api#setgamescore
type SetGameScoreMethod struct { 
    // User identifier
    UserID int64 `json:"user_id"` 
    // New score, must be non-negative
    Score int64 `json:"score"` 
    // Pass True if the high score is allowed to decrease. This can be useful when
// fixing mistakes or banning cheaters.
    Force *bool `json:"force,omitempty"` 
    // Pass True if the game message should not be automatically edited to include
// the current scoreboard
    DisableEditMessage *bool `json:"disable_edit_message,omitempty"` 
    // Required if inline_message_id is not specified. Unique identifier for the
// target chat.
    ChatID *int64 `json:"chat_id,omitempty"` 
    // Required if inline_message_id is not specified. Identifier of the sent
// message.
    MessageID *int64 `json:"message_id,omitempty"` 
    // Required if chat_id and message_id are not specified. Identifier of the
// inline message.
    InlineMessageID *string `json:"inline_message_id,omitempty"`
}

func (m SetGameScoreMethod) Call(ctx context.Context, conn Connection) (MaybeMessage, error) {
	payload := NewMultipartPayload() 
	if err := NewInt64Part(m.UserID).Write(payload, "user_id"); err != nil {
		return nil, err
	} 
	if err := NewInt64Part(m.Score).Write(payload, "score"); err != nil {
		return nil, err
	} 
	if m.Force != nil {
		if err := NewBoolPart(*m.Force).Write(payload, "force"); err != nil {
			return nil, err
		}
	} 
	if m.DisableEditMessage != nil {
		if err := NewBoolPart(*m.DisableEditMessage).Write(payload, "disable_edit_message"); err != nil {
			return nil, err
		}
	} 
	if m.ChatID != nil {
		if err := NewInt64Part(*m.ChatID).Write(payload, "chat_id"); err != nil {
			return nil, err
		}
	} 
	if m.MessageID != nil {
		if err := NewInt64Part(*m.MessageID).Write(payload, "message_id"); err != nil {
			return nil, err
		}
	} 
	if m.InlineMessageID != nil {
		if err := NewStringPart(*m.InlineMessageID).Write(payload, "inline_message_id"); err != nil {
			return nil, err
		}
	} 
	var resp json.RawMessage
	err := conn.Do(ctx, MethodSetGameScore, payload, &resp)
	if err != nil {
		return nil, fmt.Errorf("%s: %w", MethodSetGameScore, err)
	}
	result, err := unmarshalMaybeMessage(resp)
	if err != nil {
		return nil, err
	}
	return result, nil
}  
